<template>
  <div class="center">
    <div
      class="edition"
      :class="['edition-' + edition.id]"
      :style="{
        backgroundImage: `url(${
          edition.logo && grimoire.isImageOptIn
            ? edition.logo
            : require('../assets/editions/' + edition.id + '.webp')
        })`,
      }"
    ></div>
    <ul class="info">
      <li v-if="players.length - teams.traveler < 5">
        Please add more players!
      </li>
      <li>
        <span>
          {{ players.length }}
          <font-awesome-icon class="players" icon="users" />
        </span>
        <span>
          {{ teams.alive }}
          <font-awesome-icon class="alive" icon="heart-pulse" />
        </span>
        <span>
          {{ teams.votes }}
          <font-awesome-icon class="votes" icon="check-to-slot" />
        </span>
      </li>
      <li v-if="players.length - teams.traveler >= 5">
        <span>
          {{ teams.townsfolk }}
          <font-awesome-icon class="townsfolk" icon="user-friends" />
        </span>
        <span>
          {{ teams.outsider }}
          <font-awesome-icon
            class="outsider"
            :icon="teams.outsider > 1 ? 'user-friends' : 'user'"
          />
        </span>
        <span>
          {{ teams.minion }}
          <font-awesome-icon
            class="minion"
            :icon="teams.minion > 1 ? 'user-friends' : 'user'"
          />
        </span>
        <span>
          {{ teams.demon }}
          <font-awesome-icon
            class="demon"
            :icon="teams.demon > 1 ? 'user-friends' : 'user'"
          />
        </span>
        <span v-if="teams.traveler">
          {{ teams.traveler }}
          <font-awesome-icon
            class="traveler"
            :icon="teams.traveler > 1 ? 'user-friends' : 'user'"
          />
        </span>
      </li>
      <li>
        <span class="night" :class="{ isNight: grimoire.isNight }">
          Night Phase
          <font-awesome-icon :icon="['fas', 'cloud-moon']" />
        </span>
      </li>
    </ul>
  </div>
</template>

<script>
import gameJSON from "./../game";
import { mapState } from "vuex";

export default {
  computed: {
    teams: function () {
      const { players } = this.$store.state.players;
      const nonTravelers = this.$store.getters["players/nonTravelers"];
      const alive = players.filter((player) => player.isDead !== true).length;
      return {
        ...gameJSON[nonTravelers - 5],
        traveler: players.length - nonTravelers,
        alive,
        votes:
          alive +
          players.filter(
            (player) => player.isDead === true && player.isVoteless !== true,
          ).length,
      };
    },
    ...mapState(["edition", "grimoire"]),
    ...mapState("players", ["players"]),
  },
};
</script>

